chapterContent.requestInfo:
@js:
var host = String(config.host || 'https://www.sudugu.org/');
function absUrl(u, base){
  u = String(u || '').trim();
  if(!u) return '';
  if(u.indexOf('http://') === 0 || u.indexOf('https://') === 0) return u;
  if(u.indexOf('//') === 0) return 'https:' + u;
  var b = String(base || host).trim();
  if(!b) b = host;
  var h = b.indexOf('#');
  if(h >= 0) b = b.substring(0, h);
  var q = b.indexOf('?');
  if(q >= 0) b = b.substring(0, q);
  var p = b.indexOf('://');
  var origin = host;
  if(p >= 0){
    var s = b.indexOf('/', p + 3);
    origin = s >= 0 ? b.substring(0, s) : b;
  }
  if(u.charAt(0) === '/') return origin + u;
  if(b.charAt(b.length - 1) !== '/') {
    var k = b.lastIndexOf('/');
    if(k >= 0) b = b.substring(0, k + 1);
    else b = origin + '/';
  }
  return b + u;
}
var u = '';
if (params && params.lastResponse && params.lastResponse.nextPageUrl) u = params.lastResponse.nextPageUrl;
if (!u && params && params.queryInfo) u = params.queryInfo.url || params.queryInfo.detailUrl || '';
if (!u && result) {
  if (typeof result === 'string') u = result;
  else if (result.url) u = result.url;
  else if (result.detailUrl) u = result.detailUrl;
}
if (!u && params && params.responseUrl) u = params.responseUrl;
u = absUrl(u, params && params.responseUrl ? params.responseUrl : host);
return {'url': u, 'httpHeaders': config.httpHeaders};

