function parseChapter(u){
  var full = absUrl(u, host);
  if(!full) return null;
  var x = full;
  var h = x.indexOf('#');
  if(h >= 0) x = x.substring(0, h);
  var q = x.indexOf('?');
  if(q >= 0) x = x.substring(0, q);
  var arr = x.split('/');
  if(arr.length < 5) return null;
  var bookId = arr[arr.length - 2];
  var file = arr[arr.length - 1];
  if(file.indexOf('.html') < 0) return null;
  file = file.replace('.html', '');
  var parts = file.split('-');
  var chapterId = parts[0];
  var page = 1;
  if(parts.length > 1){
    var n = parseInt(parts[1], 10);
    if(!n || n < 1) return null;
    page = n;
  }
  if(!bookId || !chapterId) return null;
  return {'bookId': bookId, 'chapterId': chapterId, 'page': page};
}
var cand = absUrl(result, params && params.responseUrl ? params.responseUrl : host);
if(!cand) return '';
var curUrl = '';
if(params && params.responseUrl) curUrl = params.responseUrl;
if(!curUrl && params && params.queryInfo) curUrl = params.queryInfo.url || params.queryInfo.detailUrl || '';
if(!curUrl && typeof result === 'string') curUrl = result;
var cur = parseChapter(curUrl);
var nxt = parseChapter(cand);
if(!cur || !nxt) return '';
if(cur.bookId !== nxt.bookId) return '';
if(cur.chapterId !== nxt.chapterId) return '';
if(nxt.page <= cur.page) return '';
return cand;

